#include <vector>
#include <algorithm>

long long solve(std::vector<long long> landStartTime, std::vector<long long> landDuration, std::vector<long long> waterStartTime, std::vector<long long> waterDuration) {
    long long min_time = 1e18;
    int n = landStartTime.size();
    int m = waterStartTime.size();
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            // Case 1: Land first, then water
            long long land_end = landStartTime[i] + landDuration[i];
            long long water_start = std::max(waterStartTime[j], land_end);
            long long case1_end = water_start + waterDuration[j];

            // Case 2: Water first, then land
            long long water_end = waterStartTime[j] + waterDuration[j];
            long long land_start = std::max(landStartTime[i], water_end);
            long long case2_end = land_start + landDuration[i];

            long long current_min = std::min(case1_end, case2_end);
            if (current_min < min_time) {
                min_time = current_min;
            }
        }
    }
    return min_time;
}

